
import { defineComponent, ref } from "vue";
import { historyCheckDetail } from "@/server/http/api/Amultitasking";
const columns = [
  {
    title: "检测项名称",
    dataIndex: "checkItemName",
    key: "checkItemName",
  },
  {
    title: "技术指标",
    dataIndex: "specsContent",
    key: "specsContent",
  },

  {
    title: "检测结果",
    dataIndex: "checkResult",
    key: "checkResult",
  },
  {
    title: "结果判定",
    dataIndex: "judgeResult",
    key: "judgeResult",
  },
];
export default defineComponent({
  props: ["detail"],
  setup(props) {
    let checkDetail = ref({});
    const visible = ref<boolean>(false);

    const showModal = () => {
      visible.value = true;
      historyCheckDetail(props.detail.id).then((res: any) => {
        //console.log("报告历史详情", res);
        if (res.data.code === 200) {
          checkDetail.value = res.data.data;
        }
      });
    };

    const handleOk = (e: MouseEvent) => {
      //console.log(e);
      visible.value = false;
    };
    return {
      visible,
      showModal,
      handleOk,
      checkDetail,
      columns,
    };
  },
});
