const columns1 = [
  {
    title: "任务编号",
    dataIndex: "taskCode",
    key: "taskCode",
  },
  {
    title: "样品名称",
    dataIndex: "sampleName",
    key: "sampleName",
  },
  {
    title: "本单费用",
    dataIndex: "countPrice",
    key: "countPrice",
  },
  {
    title: "要求完成日期",
    key: "requestDate",
    dataIndex: "requestDate",
  },
  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];

import { defineComponent, provide, reactive, ref, toRefs, watch } from "vue";
import {
  reportList,
  historicalReport,
  commitApprove,
} from "@/server/http/api/Amultitasking";
import CheckDetail from "./model/Reportgeneration/CheckDetail.vue";
export default defineComponent({
  name: "Reportgeneration",
  components: { CheckDetail },
  setup() {
    let active = ref(0);
    const total = ref(0);

    let datatList = ref([]);
    let options = reactive({
      searchValue: "",
      pageNum: 1,
      pageSize: 10,
    });
    const searchReportList = () => {
      reportList({
        search: options.searchValue,
        pageNum: options.pageNum,
        pageSize: options.pageSize,
      }).then((res: any) => {
        //console.log("报告生成", res);
        if (res.data.code === 200) {
          datatList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    };
    const searchHistoricalReport = () => {
      historicalReport({
        search: options.searchValue,
        pageNum: options.pageNum,
        pageSize: options.pageSize,
      }).then((res: any) => {
        //console.log("历史查询", res);
        if (res.data.code === 200) {
          datatList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    };
    watch(active, (newval) => {
      datatList.value = [];
      if (newval == 0) {
        searchReportList();
      } else {
        searchHistoricalReport();
      }
    });

    let timer: any;
    watch(
      options,
      () => {
        if (active.value == 0) {
          clearTimeout(timer);
          timer = setTimeout(() => {
            searchReportList();
          }, 400);
        } else {
          clearTimeout(timer);
          timer = setTimeout(() => {
            searchHistoricalReport();
          }, 400);
        }
      },
      {
        immediate: true,
      }
    );
    function commit(id: number) {
      commitApprove(id).then((res: any) => {
        //console.log("报告审批", res);
      });
    }

    function onSearch() {}
    return {
      onSearch,
      datatList,
      columns,
      columns1,
      commit,
      active,
      total,
      ...toRefs(options),
    };
  },
});
